import React, { useState } from 'react';
import axios from 'axios';

const App = () => {
  const [files, setFiles] = useState([{ path: '', content: '' }]);
  const [loading, setLoading] = useState(false);

  const handleAddFile = () => {
    setFiles([...files, { path: '', content: '' }]);
  };

  const handleRemoveFile = (index) => {
    setFiles(files.filter((_, i) => i !== index));
  };

  const handleFileChange = (index, field, value) => {
    const newFiles = [...files];
    newFiles[index][field] = value;
    setFiles(newFiles);
  };

  const handleDownloadZip = async () => {
    // Filter out empty entries
    const validFiles = files.filter(f => f.path.trim() !== '');
    if (validFiles.length === 0) {
      alert("Please add at least one file with a path.");
      return;
    }

    setLoading(true);

    try {
      const response = await axios.post(
        'http://localhost:5001/create-zip',
        {
          files: validFiles,
        },
        {
          responseType: 'blob',
        }
      );

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');

      link.href = url;
      link.setAttribute('download', 'project.zip');

      document.body.appendChild(link);
      link.click();

      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      setLoading(false);
    } catch (error) {
      console.error('Error downloading the zip file:', error);
      alert('Error downloading zip file.');
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6 bg-gray-50 min-h-screen">
      <div className="bg-white rounded-lg shadow-md p-8">
        <h1 className="text-3xl font-bold mb-2 text-gray-800">
          Project Scaffolder
        </h1>
        <p className="text-gray-600 mb-8">Define your project structure and download it as a ZIP file.</p>

        <div className="space-y-6">
          {files.map((file, index) => (
            <div key={index} className="border border-gray-200 rounded-md p-4 bg-gray-50">
              <div className="flex justify-between items-center mb-3">
                <h3 className="font-semibold text-gray-700">File {index + 1}</h3>
                {files.length > 1 && (
                  <button
                    onClick={() => handleRemoveFile(index)}
                    className="text-red-500 hover:text-red-700 text-sm font-medium"
                  >
                    Remove
                  </button>
                )}
              </div>

              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">File Path</label>
                <input
                  type="text"
                  value={file.path}
                  onChange={(e) => handleFileChange(index, 'path', e.target.value)}
                  placeholder="e.g., src/components/Button.js"
                  className="w-full p-2 border border-gray-300 rounded focus:ring-blue-500 focus:border-blue-500 outline-none"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Content</label>
                <textarea
                  value={file.content}
                  onChange={(e) => handleFileChange(index, 'content', e.target.value)}
                  rows="6"
                  className="w-full p-2 border border-gray-300 rounded focus:ring-blue-500 focus:border-blue-500 outline-none font-mono text-sm"
                  placeholder="Enter file contents..."
                />
              </div>
            </div>
          ))}
        </div>

        <div className="mt-6 flex justify-between items-center pt-4 border-t border-gray-200">
          <button
            onClick={handleAddFile}
            className="bg-gray-200 text-gray-700 px-4 py-2 rounded hover:bg-gray-300 font-medium transition-colors"
          >
            + Add Another File
          </button>

          <button
            onClick={handleDownloadZip}
            disabled={loading}
            className={`px-6 py-2 rounded font-medium text-white transition-colors ${
              loading ? 'bg-blue-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'
            }`}
          >
            {loading ? 'Generating ZIP...' : 'Download Project ZIP'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;
